### **5. HEADLESS VERIFICATION: `phase_11_4_sre_healing.spec.ts`**

An end-to-end test is required to validate the entire autonomous healing loop, from fault injection to blueprint generation. This test will use Playwright for robust interaction and filesystem assertions.

**File:** `tests/e2e/phase_11_4_sre_healing.spec.ts`
```typescript
import { test, expect } from '@playwright/test';
import fs from 'fs/promises';
import path from 'path';

const DISPATCH_QUEUE_PATH = path.resolve(process.cwd(), 'ay2_dispatch_queue');
const LOGS_PATH = path.resolve(process.cwd(), 'Master_Architect_Elite_Logic/logs');
const MOCK_AGENT_ID = 'mock_faulty_agent';

// Utility to poll for a file matching a condition
async function pollForFile(dir: string, condition: (file: string) => boolean, timeout = 10000) {
    const startTime = Date.now();
    while (Date.now() - startTime < timeout) {
        try {
            const files = await fs.readdir(dir);
            const foundFile = files.find(condition);
            if (foundFile) {
                return path.join(dir, foundFile);
            }
        } catch (error) {
            // Directory might not exist yet, ignore and retry
        }
        await new Promise(resolve => setTimeout(resolve, 500));
    }
    return null;
}

test.describe('Phase 11.4: Phantom SRE Autonomous Healing', () => {

    test.beforeAll(async () => {
        // Ensure test directories exist and are clean
        await fs.mkdir(DISPATCH_QUEUE_PATH, { recursive: true });
        await fs.mkdir(LOGS_PATH, { recursive: true });
        // Clean up previous test artifacts
        for (const file of await fs.readdir(DISPATCH_QUEUE_PATH)) {
            await fs.unlink(path.join(DISPATCH_QUEUE_PATH, file));
        }
    });

    test('should detect a ZeroDivisionError and dispatch a remediation blueprint', async ({ request }) => {
        // This test assumes an API endpoint exists to trigger a test agent that is designed to fail.
        // The orchestrator must be running and configured to spawn this agent.

        // Step 1: Trigger the fault via an API call to the test harness
        const response = await request.post('/api/test_harness/trigger_fault', {
            data: { agentId: MOCK_AGENT_ID, faultType: 'ZeroDivisionError' }
        });
        // The agent process itself will fail, but the API call that triggered it might return 202 (Accepted)
        expect(response.ok()).toBeTruthy();

        // Step 2: Assert that the SRE node detects the error and creates a blueprint
        const blueprintPath = await pollForFile(
            DISPATCH_QUEUE_PATH,
            (file) => file.includes(MOCK_AGENT_ID) && file.endsWith('.json')
        );

        expect(blueprintPath, 'Remediation blueprint was not found in the dispatch queue within the timeout.').not.toBeNull();

        // Step 3: Verify the contents of the generated blueprint
        const blueprintContent = await fs.readFile(blueprintPath!, 'utf-8');
        const blueprint = JSON.parse(blueprintContent);

        expect(blueprint.target_agent).toBe(MOCK_AGENT_ID);
        expect(blueprint.status).toBe('PENDING_ACTUATION');
        expect(blueprint.error_signature).toContain('Traceback (most recent call last):');
        expect(blueprint.error_signature).toContain('ZeroDivisionError: division by zero');
    });
});
